"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[44],{62119:e=>{e.exports=JSON.parse('{"functions":[{"name":"Fetch","desc":"Finds the specified `SoundDefinition` and gives back a `Sound`. If somthing goes wrong a `Blank Sound` is returned instead.\\n\\n:::info\\n- If a sound is `Preloaded` it is instead `Cloned` from the preloadFolder\\n- If a sound is `Warmed` it is instead `Cloned` from the warmed cache.\\n:::\\n\\n:::warning\\nIf the sound is not preloaded or warmed it may take a moment to fetch and load as it needs to be created first.\\n:::\\n\\n```lua\\nlocal mySound = VluxySF.Fetch(\\"MySound\\")\\nmySound.Volume = 0.3\\n\\nlocal echoEffect = mySound.EchoSoundEffect\\nif echoEffect then\\n\\techoEffect.WetLevel = 1.3\\nend\\n\\nmySound:Play()\\n```","params":[{"name":"name","desc":"The name of the `Sound`.","lua_type":"string"},{"name":"parent","desc":"Parent of the sound.","lua_type":"Instance?"},{"name":"preset","desc":"`Preset` to apply.","lua_type":"(Sound) -> ()?"}],"returns":[{"desc":"The fetched sound instance.","lua_type":"Sound"}],"function_type":"static","tags":["RequiresSchema"],"source":{"line":217,"path":"lib/init.luau"}},{"name":"FetchStrict","desc":"Similar to `VluxySF.Fetch` but will not return a `Blank Sound` on fail.\\n\\n```lua\\nlocal mySound = VluxySF.Fetch(\\"MySound\\")\\n\\nif mySound then\\n\\tmySound.Volume = 0.3\\n\\n\\tlocal echoEffect = mySound.EchoSoundEffect\\n\\tif echoEffect then\\n\\t\\techoEffect.WetLevel = 1.3\\n\\tend\\n\\n\\tmySound:Play()\\nend\\n```","params":[{"name":"name","desc":"The name of the `Sound`.","lua_type":"string"},{"name":"parent","desc":"Parent of the `Sound`.","lua_type":"Instance?"},{"name":"preset","desc":"`Preset` to apply.","lua_type":"(Sound) -> ()?"}],"returns":[{"desc":"The fetched `Sound` instance if success.","lua_type":"Sound?"}],"function_type":"static","tags":["RequiresSchema"],"source":{"line":265,"path":"lib/init.luau"}},{"name":"FetchPlayOnce","desc":"Plays a `OneShot` `Sound` and cleans up after playing.\\n\\n```lua\\nVluxySF.FetchPlayOnce(\\"MySound\\")\\n```","params":[{"name":"name","desc":"The name of the `Sound`.","lua_type":"string"},{"name":"parent","desc":"Parent of the `Sound`.","lua_type":"Instance?"},{"name":"preset","desc":"`Preset` to apply.","lua_type":"(Sound) -> ()?"},{"name":"waitOnLoad","desc":"Wait for the `Sound` to load? Always separate thread.","lua_type":"boolean?"}],"returns":[{"desc":"Cleanup function.","lua_type":"() -> ()"}],"function_type":"static","tags":["RequiresSchema"],"source":{"line":313,"path":"lib/init.luau"}}],"properties":[],"types":[],"name":"VluxySF","desc":"`VluxySoundFactory` is a sound management system designed to simplify the process of dealing with sounds as a scripter.\\nIt primarily tries to make fetching your sounds as easy as possible and comes with some memory saving features.\\nIt also comes with some extra features like jittering and presets.","realm":["Client","Server"],"source":{"line":177,"path":"lib/init.luau"}}')}}]);